import chalk from 'chalk';
import { log, spinner } from '@clack/prompts';

import { wait } from '@/cli/lib/wait';

import { redeemInviteCode as redeemInviteCodeLib } from '@/shared/redeem-invite';
import { getTxExplorerUrl, Network } from '@agentcash/networks';

import type { RedeemInviteArgs } from '@/shared/redeem-invite';
import type { GlobalFlags } from '@/types';
import type { Wallets } from '@/wallet';

const SURFACE = 'cli:redeem-invite';

export const redeemInviteCode = async (
  args: GlobalFlags<RedeemInviteArgs>,
  wallets: Wallets
) => {
  const s = spinner();

  if (!args.yes) {
    s.start('Redeeming invite code...');
  }

  const result = await redeemInviteCodeLib(SURFACE, args, args, wallets);

  return result.match(
    async ({ amount, txHash, network }) => {
      if (!args.yes) {
        s.stop('Invite code redeemed successfully!');

        await wait({
          startText: 'Processing...',
          stopText: chalk.green(
            `${chalk.bold(amount)} USDC has been sent to your wallet!`
          ),
          ms: 1000,
        });
      }

      const resolvedNetwork =
        network === Network.SOLANA ? Network.SOLANA : Network.BASE;
      log.info(
        chalk.dim(`Transaction: ${getTxExplorerUrl(txHash, resolvedNetwork)}`)
      );

      return true;
    },
    error => {
      if (!args.yes) {
        s.stop('Invite code redemption failed');
      }
      log.warning(
        chalk.yellow(`Failed to redeem invite code: ${error.message}`)
      );
      return false;
    }
  );
};
