import chalk from 'chalk';
import { intro, outro } from '@clack/prompts';

import { log } from '@/shared/log';

import { getClient } from './1-get-client';
import { addServer } from './2-add-server';
import { redeemInviteCode } from './3-redeem-invite';
import { addFunds } from './4-add-funds';

import { getWallet } from '@/wallet';

import type { Command } from '@/types';
import type { Clients } from './clients';

export interface InstallArgs {
  client?: Clients;
}

export const installMcpServer: Command<InstallArgs> = async args => {
  intro(chalk.green.bold(`Install agentcash MCP`));

  const walletResult = await getWallet();

  if (walletResult.isErr()) {
    log.error(JSON.stringify(walletResult.error, null, 2));
    outro(chalk.bold.red('Failed to get wallet'));
    process.exit(1);
  }

  const client = await getClient(args);

  await addServer(client, args);

  const inviteRedeemed = args.invite
    ? await redeemInviteCode(
        {
          ...args,
          code: args.invite,
        },
        walletResult.value
      )
    : false;

  if (!inviteRedeemed) {
    await addFunds({
      args,
      wallets: walletResult.value,
    });
  }

  outro(chalk.bold.green('Your agentcash MCP server is ready to use!'));
};
