import chalk from 'chalk';
import { log, spinner } from '@clack/prompts';

import { getBalance } from '@/shared/balance';
import { promptDeposit } from '@/cli/lib/deposit';

import { Network } from '@agentcash/networks';

import type { Wallets } from '@/wallet';
import type { GlobalFlags } from '@/types';

interface AddFundsProps {
  args: GlobalFlags;
  wallets: Wallets;
}

export const addFunds = async ({ args, wallets }: AddFundsProps) => {
  const { start, stop } = spinner();

  start('Checking balance...');
  const balanceResult = await getBalance(
    'add-funds',
    {
      address: wallets.evm.address,
      network: Network.BASE,
    },
    args
  );

  if (balanceResult.isOk()) {
    stop(`Balance: ${chalk.bold(`${balanceResult.value.balance} USDC`)} `);
  } else {
    stop(`Error: ${balanceResult.error.message}`);
    return;
  }

  const balance = balanceResult.value.balance;

  if (balance === 0) {
    log.info('To use paid API tools, you will need USDC in your wallet.');
    await promptDeposit('add-funds', args, wallets);
  } else {
    if (balance < 1) {
      log.warning(
        chalk.bold(`Your balance is low ($${balance}). Consider topping up.`)
      );
      await promptDeposit('install', args, wallets);
    }
  }
};
